#include<bits/stdc++.h>
using namespace std;
int n,m;
long long dp[205][205][205];
int main()
{
	cin>>n>>m;
	dp[0][0][2]=1;
	for(int i=1;i<=n+m;i++)
	{
		for(int j=1;j<m;j++)
		{
			for(int q=0;q<=m;q++)
			{
				dp[i][j][q]=dp[i-1][j-1][q+1]%10000000007;
				if(q%2==0&&q!=0) dp[i][j][q]=(dp[i][j][q]+dp[i-1][j][q/2])%10000000007;
			}
		}
	}
	cout<<dp[n+m][m][0]%10000000007;
}
